INSERT INTO reviews (id, product_id, user_id, rating, title, body, image_url, is_approved, created_at)
VALUES
    ('92000000-0000-0000-0000-000000000001', '40000000-0000-0000-0000-000000000001', '00000000-0000-0000-0000-000000000002', 5, 'Perfect everyday pendant', 'The finish is premium and the pendant feels more expensive than it is. Delivery was quick too.', NULL, TRUE, CURRENT_TIMESTAMP - INTERVAL '14 days'),
    ('92000000-0000-0000-0000-000000000002', '40000000-0000-0000-0000-000000000001', '00000000-0000-0000-0000-000000000001', 4, 'Elegant gift pick', 'Picked this for gifting and the packaging made the whole experience feel polished.', NULL, TRUE, CURRENT_TIMESTAMP - INTERVAL '13 days'),
    ('92000000-0000-0000-0000-000000000003', '40000000-0000-0000-0000-000000000003', '00000000-0000-0000-0000-000000000002', 5, 'Looks exactly like the photos', 'Good sparkle, not too loud, and the chain length sits really well.', NULL, TRUE, CURRENT_TIMESTAMP - INTERVAL '12 days'),
    ('92000000-0000-0000-0000-000000000004', '40000000-0000-0000-0000-000000000004', '00000000-0000-0000-0000-000000000002', 4, 'Diamond shine is subtle', 'I wanted something minimal for workwear and this hit the mark without feeling plain.', NULL, TRUE, CURRENT_TIMESTAMP - INTERVAL '11 days'),
    ('92000000-0000-0000-0000-000000000005', '40000000-0000-0000-0000-000000000005', '00000000-0000-0000-0000-000000000001', 5, 'Great fit and finish', 'The ring sizing was accurate and the rose finish looks excellent in person.', NULL, TRUE, CURRENT_TIMESTAMP - INTERVAL '10 days'),
    ('92000000-0000-0000-0000-000000000006', '40000000-0000-0000-0000-000000000009', '00000000-0000-0000-0000-000000000002', 5, 'Very flattering pair', 'Lightweight for the size and easy to wear through long events.', NULL, TRUE, CURRENT_TIMESTAMP - INTERVAL '9 days'),
    ('92000000-0000-0000-0000-000000000007', '40000000-0000-0000-0000-000000000010', '00000000-0000-0000-0000-000000000002', 4, 'Good daily studs', 'These are now my daily studs. The closure feels secure and comfortable.', NULL, TRUE, CURRENT_TIMESTAMP - INTERVAL '8 days'),
    ('92000000-0000-0000-0000-000000000008', '40000000-0000-0000-0000-000000000014', '00000000-0000-0000-0000-000000000001', 5, 'Nice personalization option', 'The bracelet engraving was clean and it made a thoughtful birthday gift.', NULL, TRUE, CURRENT_TIMESTAMP - INTERVAL '7 days'),
    ('92000000-0000-0000-0000-000000000009', '40000000-0000-0000-0000-000000000017', '00000000-0000-0000-0000-000000000001', 4, 'Modern mangalsutra design', 'The profile feels contemporary enough for everyday wear, which is what I wanted.', NULL, TRUE, CURRENT_TIMESTAMP - INTERVAL '6 days'),
    ('92000000-0000-0000-0000-000000000010', '40000000-0000-0000-0000-000000000019', '00000000-0000-0000-0000-000000000002', 5, 'Customization came out clean', 'Name engraving was centered well and the necklace has a premium shine.', NULL, TRUE, CURRENT_TIMESTAMP - INTERVAL '5 days')
INSERT INTO blogs (id, title, slug, content, author, cover_image_url, published_at, is_published)
VALUES
    ('94000000-0000-0000-0000-000000000001', 'How To Style Silver Jewelry For Everyday Looks', 'style-silver-jewelry-everyday', '<p>Silver jewelry works best when layered intentionally. Start with one hero pendant and then build smaller details around it.</p><p>Keep proportions balanced for office wear, and switch to textured earrings or a bracelet stack for evenings.</p>', 'Aurora Gems Editorial', 'https://placehold.co/1600x900/png?text=Silver+Jewelry+Guide', CURRENT_TIMESTAMP - INTERVAL '30 days', TRUE),
    ('94000000-0000-0000-0000-000000000002', '5 Anniversary Jewelry Gifts That Feel Personal', 'anniversary-jewelry-gifts', '<p>Personalized pieces, zodiac motifs, and lab-grown diamond essentials are strong anniversary picks because they combine sentiment with repeat wearability.</p><p>Match the metal tone to the receiver''s current wardrobe and keep engraving brief and intentional.</p>', 'Aurora Gems Editorial', 'https://placehold.co/1600x900/png?text=Anniversary+Gift+Guide', CURRENT_TIMESTAMP - INTERVAL '18 days', TRUE),
    ('94000000-0000-0000-0000-000000000003', 'Understanding Lab-Grown Diamond Jewelry', 'understanding-lab-grown-diamond-jewelry', '<p>Lab-grown diamonds share the same physical composition as mined diamonds while offering a more accessible entry point for premium jewelry buyers.</p><p>For daily wear, prioritize secure settings and understated silhouettes that stay versatile across occasions.</p>', 'Aurora Gems Editorial', 'https://placehold.co/1600x900/png?text=Lab+Diamond+Guide', CURRENT_TIMESTAMP - INTERVAL '9 days', TRUE)
